#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int max_sum = -1;
        int count = 0;
        int total_pairs = (N * (N - 1)) / 2;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int sum = arr[i] + arr[j];
                if (sum > max_sum) {
                    max_sum = sum;
                    count = 1;
                } else if (sum == max_sum) {
                    count++;
                }
            }
        }
        double probability = (double)count / total_pairs;
        printf("%.8f\n", probability);
    }
    return 0;
}

