import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = scanner.nextInt();
            }
            int max_sum = -1;
            int count = 0;
            int total_pairs = (N * (N - 1)) / 2;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    int sum = arr[i] + arr[j];
                    if (sum > max_sum) {
                        max_sum = sum;
                        count = 1;
                    } else if (sum == max_sum) {
                        count++;
                    }
                }
            }
            double probability = (double)count / total_pairs;
            System.out.printf("%.8f\n", probability);
        }
    }
}

